"use client";

import React, { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { CartService } from "@/services/cart.service";
import { OrderService } from "@/services/order.service";
import { useForm } from "react-hook-form";
import * as Yup from "yup";
import { yupResolver } from "@hookform/resolvers/yup";
import { Input } from "@/components/ui/Input";
import { Button } from "@/components/ui/Button";
import { CreditCard, Banknote, ShieldCheck, Loader2 } from "lucide-react";
import toast from "react-hot-toast";
import { useRouter } from "next/navigation";
import { motion } from "framer-motion";

const addressSchema = Yup.object().shape({
  details: Yup.string().required("Address details are required"),
  phone: Yup.string().matches(/^01[0125][0-9]{8}$/, "Invalid Egyptian phone number").required("Phone is required"),
  city: Yup.string().required("City is required"),
});

type CheckoutForm = Yup.InferType<typeof addressSchema>;

import Image from "next/image";

export default function CheckoutPage() {
  const router = useRouter();
  const [paymentMethod, setPaymentMethod] = useState<"cash" | "online">("online");

  const { data: cartData, isLoading: isCartLoading } = useQuery({
    queryKey: ["cart"],
    queryFn: CartService.getCart,
  });

  const { register, handleSubmit, formState: { errors } } = useForm<CheckoutForm>({
    resolver: yupResolver(addressSchema)
  });

  const cashOrderMutation = useMutation({
    mutationFn: (data: CheckoutForm) => OrderService.createCashOrder(cartData!.data._id, data),
    onSuccess: () => {
      toast.success("Order placed successfully!");
      router.push("/allorders"); // Standard Route API redirect for successful orders
    },
    onError: (err: unknown) => {
      if (err && typeof err === "object" && "response" in err) {
        toast.error((err as { response?: { data?: { message?: string } } }).response?.data?.message || "Failed to place order");
      } else {
        toast.error("Failed to place order");
      }
    }
  });

  const onlineOrderMutation = useMutation({
    mutationFn: (data: CheckoutForm) => OrderService.checkoutSession(cartData!.data._id, data),
    onSuccess: (data) => {
      // Redirect to Stripe checkout page
      if (data.session && data.session.url) {
        window.location.href = data.session.url;
      }
    },
    onError: (err: unknown) => {
      if (err && typeof err === "object" && "response" in err) {
        toast.error((err as { response?: { data?: { message?: string } } }).response?.data?.message || "Failed to initiate payment");
      } else {
        toast.error("Failed to initiate payment");
      }
    }
  });

  const onSubmit = (data: CheckoutForm) => {
    if (!cartData?.data._id) {
      toast.error("Your cart is empty");
      return;
    }

    if (paymentMethod === "cash") {
      cashOrderMutation.mutate(data);
    } else {
      onlineOrderMutation.mutate(data);
    }
  };

  if (isCartLoading) {
    return (
      <div className="flex-1 flex justify-center items-center h-[50vh]">
        <Loader2 className="w-12 h-12 animate-spin text-orange-600" />
      </div>
    );
  }

  const cart = cartData?.data;
  if (!cart || cart.products.length === 0) {
    router.push("/cart");
    return null;
  }

  const isProcessing = cashOrderMutation.isPending || onlineOrderMutation.isPending;

  return (
    <div className="bg-slate-50 dark:bg-slate-950 flex-1 py-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-8">Secure Checkout</h1>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          
          {/* Form & Payment Method */}
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="space-y-8"
          >
            {/* Shipping Details */}
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-800">
              <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                <span className="w-8 h-8 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center text-sm shadow-sm">1</span> 
                Shipping Information
              </h2>
              
              <form id="checkout-form" onSubmit={handleSubmit(onSubmit)} className="space-y-5">
                <Input
                  label="City"
                  placeholder="Cairo"
                  {...register("city")}
                  error={errors.city?.message}
                />
                <Input
                  label="Detailed Address"
                  placeholder="123 Street Name, Apartment 4"
                  {...register("details")}
                  error={errors.details?.message}
                />
                <Input
                  label="Phone Number"
                  placeholder="01012345678"
                  {...register("phone")}
                  error={errors.phone?.message}
                />
              </form>
            </div>

            {/* Payment Method */}
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-800">
              <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                <span className="w-8 h-8 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center text-sm shadow-sm">2</span> 
                Payment Method
              </h2>
              
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <button
                  type="button"
                  onClick={() => setPaymentMethod("online")}
                  className={`relative p-6 rounded-xl border-2 flex flex-col items-center gap-3 transition-all ${
                    paymentMethod === "online" 
                      ? "border-orange-500 bg-orange-50 dark:bg-orange-500/10 text-orange-700 dark:text-orange-400" 
                      : "border-slate-200 dark:border-slate-700 hover:border-orange-300 text-slate-600 dark:text-slate-400"
                  }`}
                >
                  <CreditCard className="w-8 h-8" />
                  <span className="font-bold">Pay Online</span>
                  {paymentMethod === "online" && (
                    <div className="absolute top-3 right-3 text-orange-500"><ShieldCheck className="w-5 h-5" /></div>
                  )}
                </button>

                <button
                  type="button"
                  onClick={() => setPaymentMethod("cash")}
                  className={`relative p-6 rounded-xl border-2 flex flex-col items-center gap-3 transition-all ${
                    paymentMethod === "cash" 
                      ? "border-orange-500 bg-orange-50 dark:bg-orange-500/10 text-orange-700 dark:text-orange-400" 
                      : "border-slate-200 dark:border-slate-700 hover:border-orange-300 text-slate-600 dark:text-slate-400"
                  }`}
                >
                  <Banknote className="w-8 h-8" />
                  <span className="font-bold">Cash on Delivery</span>
                  {paymentMethod === "cash" && (
                    <div className="absolute top-3 right-3 text-orange-500"><ShieldCheck className="w-5 h-5" /></div>
                  )}
                </button>
              </div>
            </div>
          </motion.div>

          {/* Order Summary & Submit */}
          <motion.div 
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
          >
            <div className="bg-slate-900 text-white p-8 rounded-3xl shadow-xl sticky top-24">
              <h2 className="text-xl font-bold mb-6">Review Your Order</h2>
              
              <div className="space-y-4 max-h-64 overflow-y-auto pr-2 custom-scrollbar mb-6">
                {cart.products.map((item) => (
                  <div key={item._id} className="flex justify-between items-center bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
                    <div className="flex items-center gap-3">
                      <div className="w-12 h-12 bg-white rounded-lg overflow-hidden relative">
                        <Image src={item.product.imageCover} alt={item.product.title} fill className="object-cover" sizes="48px" />
                      </div>
                      <div>
                        <p className="font-medium text-sm line-clamp-1 max-w-[150px]">{item.product.title}</p>
                        <p className="text-xs text-slate-400">Qty: {item.count}</p>
                      </div>
                    </div>
                    <span className="font-semibold text-sm">EGP {item.price * item.count}</span>
                  </div>
                ))}
              </div>

              <div className="space-y-3 mb-6 pt-6 border-t border-slate-700">
                <div className="flex justify-between text-slate-400 text-sm">
                  <span>Subtotal</span>
                  <span>EGP {cart.totalCartPrice}</span>
                </div>
                <div className="flex justify-between text-slate-400 text-sm">
                  <span>Shipping</span>
                  <span className="text-green-400">Free</span>
                </div>
                <div className="flex justify-between text-slate-400 text-sm">
                  <span>Tax</span>
                  <span>Calculated at checkout</span>
                </div>
              </div>

              <div className="flex justify-between items-end mb-8 pt-6 border-t border-slate-700">
                <span className="text-lg font-medium">Total to Pay</span>
                <span className="text-3xl font-black text-orange-400">EGP {cart.totalCartPrice}</span>
              </div>

              <Button 
                type="submit" 
                form="checkout-form"
                isLoading={isProcessing}
                className="w-full h-14 text-lg bg-orange-600 hover:bg-orange-500 text-white rounded-xl font-bold transition-all shadow-lg shadow-orange-500/20"
              >
                {paymentMethod === "online" ? "Proceed to Payment" : "Place Order"}
              </Button>

              <div className="mt-6 flex items-center justify-center gap-2 text-xs text-slate-400">
                <ShieldCheck className="w-4 h-4" />
                Payments are secure and encrypted
              </div>
            </div>
          </motion.div>

        </div>
      </div>
    </div>
  );
}
