import { axiosInstance } from "@/lib/axios";

export interface ShippingAddress {
  details: string;
  phone: string;
  city: string;
}

export const OrderService = {
  // Create Cash On Delivery Order
  createCashOrder: async (cartId: string, shippingAddress: ShippingAddress) => {
    const { data } = await axiosInstance.post(`/api/v1/orders/${cartId}`, {
      shippingAddress,
    });
    return data;
  },

  // Get Stripe Checkout Session for Online Payment
  checkoutSession: async (cartId: string, shippingAddress: ShippingAddress) => {
    // The redirect URL where stripe should return after payment
    const url = window.location.origin;
    const { data } = await axiosInstance.post(
      `/api/v1/orders/checkout-session/${cartId}?url=${url}`,
      { shippingAddress }
    );
    return data;
  },

  getUserOrders: async (userId: string) => {
    const { data } = await axiosInstance.get(`/api/v1/orders/user/${userId}`);
    return data;
  }
};
